  economy_finance: {
    name: "Economía y finanzas",
    description: "Sistemas económicos, mercados y situación financiera",
    icon: TrendingUp,
    color: "from-emerald-500 to-green-600",
    level: "advanced",
    words: [
      { id: "econ1", spanish: "Economía", english: "Economy", difficulty: "easy", example: "The economy is growing very steadily with low unemployment and rising wages this year successfully.", exampleTranslation: "La economía está creciendo muy establemente con bajo desempleo y salarios en aumento este año exitosamente." },
      { id: "econ2", spanish: "Inflación", english: "Inflation", difficulty: "easy", example: "Inflation causes all prices to rise making goods and services more expensive for everyone unfortunately.", exampleTranslation: "La inflación causa que todos los precios suban haciendo bienes y servicios más caros para todos desafortunadamente." },
      { id: "econ3", spanish: "Impuesto", english: "Tax", difficulty: "easy", example: "All citizens must pay taxes to the government based on their income and purchases every year annually.", exampleTranslation: "Todos los ciudadanos deben pagar impuestos al gobierno basados en sus ingresos y compras cada año anualmente." },
      { id: "econ4", spanish: "Moneda", english: "Currency", difficulty: "easy", example: "The euro is the official currency used in many European countries for daily transactions and purchases.", exampleTranslation: "El euro es la moneda oficial usada en muchos países europeos para transacciones diarias y compras." },
      { id: "econ5", spanish: "Bolsa de valores", english: "Stock market", difficulty: "easy", example: "The stock market allows people to buy and sell shares of companies publicly and openly every day.", exampleTranslation: "La bolsa de valores permite a la gente comprar y vender acciones de empresas públicamente y abiertamente cada día." },
      { id: "econ6", spanish: "Desempleo", english: "Unemployment", difficulty: "easy", example: "High unemployment is a very serious problem affecting many families and the economy very negatively.", exampleTranslation: "El desempleo alto es un problema muy serio afectando muchas familias y la economía muy negativamente." },
      { id: "econ7", spanish: "PIB", english: "GDP", difficulty: "medium", example: "The GDP measures the total economic output of a country over a specific period every year annually.", exampleTranslation: "El PIB mide la producción económica total de un país durante un período específico cada año anualmente." },
      { id: "econ8", spanish: "Recesión", english: "Recession", difficulty: "medium", example: "The economic recession led to business closures and job losses affecting millions of people nationwide very negatively.", exampleTranslation: "La recesión económica condujo a cierres de negocios y pérdidas de empleos afectando millones de personas nacionalmente muy negativamente." },
      { id: "econ9", spanish: "Tipo de cambio", english: "Exchange rate", difficulty: "medium", example: "The exchange rate between dollars and euros fluctuates daily based on market conditions and economic factors constantly.", exampleTranslation: "El tipo de cambio entre dólares y euros fluctúa diariamente basado en condiciones del mercado y factores económicos constantemente." },
      { id: "econ10", spanish: "Exportación", english: "Export", difficulty: "medium", example: "The country's main exports include wine, olive oil, and manufactured goods shipped internationally to markets globally.", exampleTranslation: "Las principales exportaciones del país incluyen vino, aceite de oliva y bienes manufacturados enviados internacionalmente a mercados globalmente." },
      { id: "econ11", spanish: "Importación", english: "Import", difficulty: "medium", example: "The government imposes tariffs on imports to protect domestic industries and encourage local production and manufacturing.", exampleTranslation: "El gobierno impone aranceles sobre las importaciones para proteger industrias domésticas y fomentar producción y manufactura local." },
      { id: "econ12", spanish: "Déficit", english: "Deficit", difficulty: "medium", example: "The budget deficit occurs when government spending exceeds revenue collected through taxation annually and significantly impacts economy.", exampleTranslation: "El déficit presupuestario ocurre cuando el gasto gubernamental excede los ingresos recaudados mediante impuestos anualmente e impacta significativamente la economía." },
      { id: "econ13", spanish: "La economía está en crisis", english: "The economy is in crisis", difficulty: "hard", example: "The economy is in very serious crisis! Many businesses are closing and people are losing jobs very rapidly everywhere!", exampleTranslation: "¡La economía está en crisis muy seria! ¡Muchos negocios están cerrando y la gente está perdiendo empleos muy rápidamente en todas partes!" },
      { id: "econ14", spanish: "Los precios están subiendo", english: "Prices are rising", difficulty: "hard", example: "Prices are rising very dramatically! Everything is getting much more expensive and people are struggling financially every day!", exampleTranslation: "¡Los precios están subiendo muy dramáticamente! ¡Todo se está volviendo mucho más caro y la gente está luchando financieramente cada día!" },
      { id: "econ15", spanish: "Necesitamos reformas económicas", english: "We need economic reforms", difficulty: "hard", example: "We desperately need economic reforms to improve the situation immediately! The current policies are simply not working at all!", exampleTranslation: "¡Necesitamos desesperadamente reformas económicas para mejorar la situación inmediatamente! ¡Las políticas actuales simplemente no están funcionando en absoluto!" }
    ]
  },

